import asyncio
from semantic_kernel import Kernel
from semantic_kernel.connectors.ai.open_ai import OpenAIChatCompletion
from semantic_kernel.functions import kernel_function
from semantic_kernel.planners.function_calling_stepwise_planner import (
    FunctionCallingStepwisePlanner,
    FunctionCallingStepwisePlannerOptions,
)

# --- Plugin definitions ---

class StockPlugin:
    @kernel_function(name="get_price", description="Get the current stock price for a ticker.")
    def get_price(self, ticker: str) -> str:
        prices = {"AAPL": 189.50, "MSFT": 415.20, "GOOGL": 175.80}
        price = prices.get(ticker.upper(), None)
        if price is None:
            return f"Unknown ticker: {ticker}"
        return f"{ticker.upper()} is trading at USD {price}"

class CalculatorPlugin:
    @kernel_function(name="percentage_diff", description="Calculate the percentage difference between two numbers.")
    def percentage_diff(self, a: float, b: float) -> str:
        if b == 0:
            return "Cannot divide by zero"
        diff = ((a - b) / abs(b)) * 100
        return f"{diff:.2f}%"

class TextPlugin:
    @kernel_function(name="bullet_list", description="Format a list of items as a bullet-point summary.")
    def bullet_list(self, items: str) -> str:
        lines = [line.strip() for line in items.split(",") if line.strip()]
        return "\n".join(f"- {line}" for line in lines)

# --- Kernel setup ---
async def main():
    kernel = Kernel()
    kernel.add_service(OpenAIChatCompletion(service_id="chat", ai_model_id="gpt-4o"))
    kernel.add_plugin(StockPlugin(), plugin_name="stock")
    kernel.add_plugin(CalculatorPlugin(), plugin_name="calc")
    kernel.add_plugin(TextPlugin(), plugin_name="text")

    planner = FunctionCallingStepwisePlanner(
        service_id="chat",
        options=FunctionCallingStepwisePlannerOptions(max_iterations=12),
    )

    result = await planner.invoke(
        kernel,
        "Compare AAPL and MSFT stock prices, calculate the percentage difference, "
        "and produce a bullet-point summary of the findings.",
    )
    print(result.final_answer)
    print(f"Completed in {len(result.chat_history)} messages")

asyncio.run(main())
